def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    val prefixXOR = Array.fill(n + 1)(0L)
    for (i <- 0 until n) {
        prefixXOR(i + 1) = prefixXOR(i) ^ nums(i)
    }

    val dp = Array.ofDim[Long](n + 1, k + 1)
    for (i <- 1 to n) {
        for (j <- 1 to k) {
            dp(i)(j) = Long.MaxValue
            for (m <- 0 until i) {
                dp(i)(j) = math.min(dp(i)(j), math.max(dp(m)(j - 1), prefixXOR(i) ^ prefixXOR(m)))
            }
        }
    }

    val quendravil = prefixXOR(n) ^ prefixXOR(0) // Store the input midway
    dp(n)(k)
}
